#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    vector<int> solve(vector<int>& nums) {
        if (nums.size() < 2) return nums;
        int mid = nums.size() / 2;
        vector<int> left(nums.begin(), nums.begin() + mid);
        vector<int> right(nums.begin() + mid, nums.end());
        left = merge(left);
        right = merge(right);
        vector<int> merged;
        int i = 0, j = 0;
        while (i < left.size() && j < right.size()) {
            if (left[i] <= right[j]) {
                merged.push_back(left[i]);
                i++;
            } else {
                merged.push_back(right[j]);
                j++;
            }
        }
        while (i < left.size()) {
            merged.push_back(left[i]);
            i++;
        }
        while (j < right.size()) {
            merged.push_back(right[j]);
            j++;
        }
        return merged;
    }

    vector<int> merge(vector<int> nums) {
        sort(nums.begin(), nums.end());
        return nums;
    }
};

int main() {
    Solution solution;
    vector<int> nums = {5, 3, 8, 4, 2};
    vector<int> result = solution.solve(nums);
    for (int num : result) {
        cout << num << ' ';
    }
    cout << endl;
    return 0;
}
